166→/**
167→ * Get relative time string
168→ */
169→function getRelativeTime(date: Date): string {
170→  const now = new Date();
171→  const diffMs = now.getTime() - date.getTime();
172→  const diffSec = Math.floor(diffMs / 1000);
173→  const diffMin = Math.floor(diffSec / 60);
174→  const diffHour = Math.floor(diffMin / 60);
175→  const diffDay = Math.floor(diffHour / 24);
176→
177→  if (diffSec < 60) return "just now";
178→  if (diffMin < 60) return `${diffMin} minute${diffMin > 1 ? "s" : ""} ago`;
