194→  // Group by status
195→  const byStatus: Record<IssueStatus, IssueState[]> = {
196→    in_progress: [],
197→    waiting_for_qa_gate: [],
198→    ready_for_merge: [],
199→    blocked: [],
200→    not_started: [],
201→    merged: [],
202→    abandoned: [],
203→  };
204→
205→  for (const issue of issues) {
206→    byStatus[issue.status].push(issue);
207→  }
208→
209→  // Display in priority order using a table
210→  const statusOrder: IssueStatus[] = [
211→    "in_progress",
212→    "waiting_for_qa_gate",
213→    "ready_for_merge",
214→    "blocked",
215→    "not_started",
216→    "merged",
217→    "abandoned",
218→  ];
219→
220→  // Build rows for the table
