260→    byStatus.ready_for_merge.length > 0
261→      ? colors.success(`Ready: ${byStatus.ready_for_merge.length}`)
262→      : null,
263→    byStatus.blocked.length > 0
264→      ? colors.warning(`Blocked: ${byStatus.blocked.length}`)
