273→export async function statusCommand(
274→  options: StatusCommandOptions = {},
275→): Promise<void> {
276→  // Handle --rebuild flag
277→  if (options.rebuild) {
278→    await handleRebuild(options);
279→    return;
280→  }
281→
282→  // Handle --cleanup flag
283→  if (options.cleanup) {
284→    await handleCleanup(options);
285→    return;
286→  }
287→
288→  // If --issues or --issue flag, focus on issue state
289→  if (options.issues || options.issue !== undefined) {
290→    await displayIssueState(options);
291→    return;
292→  }
293→
294→  console.log(ui.headerBox("SEQUANT STATUS"));
295→  console.log();
296→
297→  // Package version
298→  console.log(chalk.gray(`Package version: ${getPackageVersion()}`));
299→
300→  // Check initialization
301→  const manifest = await getManifest();
302→  if (!manifest) {
303→    console.log(chalk.yellow("Status: Not initialized"));
304→    console.log(chalk.gray("\nRun `sequant init` to get started."));
305→    return;
306→  }
307→
308→  console.log(chalk.green("Status: Initialized"));
309→  console.log(chalk.gray(`Skills version: ${manifest.version}`));
310→  console.log(chalk.gray(`Stack: ${manifest.stack}`));
311→  console.log(chalk.gray(`Installed: ${manifest.installedAt}`));
312→  if (manifest.updatedAt) {
313→    console.log(chalk.gray(`Last updated: ${manifest.updatedAt}`));
314→  }
315→
316→  // Count skills
317→  const skillsDir = ".claude/skills";
318→  if (await fileExists(skillsDir)) {
319→    try {
320→      const skills = await readdir(skillsDir);
321→      const skillCount = skills.filter((s) => !s.startsWith(".")).length;
322→      console.log(chalk.gray(`Skills: ${skillCount}`));
323→    } catch {
324→      // Ignore errors
325→    }
326→  }
327→
328→  // Check for local customizations
329→  const localDir = ".claude/.local";
330→  if (await fileExists(localDir)) {
331→    console.log(chalk.blue("Custom overrides: Yes (.claude/.local/)"));
332→  }
333→
334→  // Show issue state summary
335→  const stateManager = new StateManager();
336→  if (stateManager.stateExists()) {
337→    try {
338→      const allIssues = await stateManager.getAllIssueStates();
339→      const issues = Object.values(allIssues);
340→
341→      if (issues.length > 0) {
342→        await refreshMergedStatuses(stateManager, issues);
343→        displayIssueSummary(issues);
344→      }
345→    } catch {
346→      // Ignore state read errors
347→    }
348→  }
349→
350→  console.log(chalk.gray("\nRun `sequant doctor` for detailed health check."));
351→  console.log(
352→    chalk.gray("Run `sequant status --issues` to see all tracked issues."),
353→  );
354→}
