356→/**
357→ * Display detailed issue state
358→ */
359→async function displayIssueState(options: StatusCommandOptions): Promise<void> {
360→  const stateManager = new StateManager();
361→
362→  if (!stateManager.stateExists()) {
363→    if (options.json) {
364→      console.log(JSON.stringify({ issues: {} }, null, 2));
365→    } else {
366→      console.log(chalk.yellow("\nNo workflow state found."));
367→      console.log(chalk.gray("Run `sequant run <issue>` to start tracking."));
368→    }
369→    return;
370→  }
371→
372→  try {
373→    if (options.issue !== undefined) {
374→      // Show single issue details
375→      const issueState = await stateManager.getIssueState(options.issue);
376→
377→      if (issueState) {
378→        await refreshMergedStatuses(stateManager, [issueState]);
379→      }
380→
381→      if (options.json) {
382→        console.log(JSON.stringify(issueState, null, 2));
383→      } else if (issueState) {
384→        console.log(chalk.bold(`\n📊 Issue #${options.issue} State\n`));
385→        console.log(formatIssueState(issueState));
386→      } else {
387→        console.log(
388→          chalk.yellow(`\nIssue #${options.issue} not found in state.`),
389→        );
390→      }
391→    } else {
392→      // Show all issues
393→      const allIssues = await stateManager.getAllIssueStates();
394→      const issues = Object.values(allIssues);
395→
396→      await refreshMergedStatuses(stateManager, issues);
397→
398→      if (options.json) {
399→        console.log(JSON.stringify({ issues: allIssues }, null, 2));
400→      } else {
401→        console.log(chalk.bold("\n📊 Workflow State\n"));
402→        displayIssueSummary(issues);
403→      }
404→    }
405→  } catch (error) {
406→    if (options.json) {
407→      console.log(JSON.stringify({ error: String(error) }, null, 2));
408→    } else {
409→      console.log(chalk.red(`\nError reading state: ${error}`));
410→    }
411→  }
412→}
413→
414→/**
415→ * Handle --rebuild flag: Rebuild state from run logs
416→ */
417→async function handleRebuild(options: StatusCommandOptions): Promise<void> {
418→  if (!options.json) {
419→    console.log(chalk.bold("\n🔄 Rebuilding state from logs...\n"));
420→  }
421→
422→  const result = await rebuildStateFromLogs({ verbose: !options.json });
423→
424→  if (options.json) {
425→    console.log(JSON.stringify(result, null, 2));
426→    return;
427→  }
428→
429→  if (result.success) {
430→    console.log(chalk.green("✓ State rebuilt successfully"));
431→    console.log(chalk.gray(`  Logs processed: ${result.logsProcessed}`));
432→    console.log(chalk.gray(`  Issues found: ${result.issuesFound}`));
433→
434→    if (result.issuesFound > 0) {
435→      console.log(
436→        chalk.gray("\nRun `sequant status --issues` to see rebuilt state."),
437→      );
438→    }
439→  } else {
440→    console.log(chalk.red(`✗ Rebuild failed: ${result.error}`));
441→  }
442→}
443→
444→/**
445→ * Handle --cleanup flag: Clean up stale/orphaned entries
446→ */
447→async function handleCleanup(options: StatusCommandOptions): Promise<void> {
448→  const dryRun = options.dryRun ?? false;
449→  const removeAll = options.all ?? false;
450→
451→  if (!options.json) {
452→    if (dryRun) {
453→      console.log(chalk.bold("\n🧹 Cleanup preview (dry run)...\n"));
454→    } else if (removeAll) {
455→      console.log(chalk.bold("\n🧹 Cleaning up all orphaned entries...\n"));
456→    } else {
457→      console.log(chalk.bold("\n🧹 Cleaning up stale entries...\n"));
458→    }
459→  }
460→
461→  const result = await cleanupStaleEntries({
462→    dryRun,
463→    maxAgeDays: options.maxAge,
464→    removeAll,
465→    verbose: !options.json,
466→  });
467→
468→  if (options.json) {
469→    console.log(JSON.stringify(result, null, 2));
470→    return;
471→  }
472→
473→  if (result.success) {
474→    const orphanedCount = result.orphaned.length;
475→    const removedCount = result.removed.length;
476→    const mergedCount = result.merged.length;
477→
478→    if (orphanedCount === 0 && removedCount === 0 && mergedCount === 0) {
479→      console.log(chalk.green("✓ No stale entries found"));
480→    } else {
481→      if (dryRun) {
482→        console.log(chalk.yellow("Preview (no changes made):"));
483→      } else {
484→        console.log(chalk.green("✓ Cleanup completed"));
485→      }
486→
487→      if (mergedCount > 0) {
488→        console.log(
489→          chalk.green(
490→            `  Merged PRs (auto-removed): ${result.merged.map((n) => `#${n}`).join(", ")}`,
491→          ),
492→        );
493→      }
494→
495→      if (orphanedCount > 0) {
496→        const orphanedNotMerged = result.orphaned.filter(
497→          (n) => !result.merged.includes(n),
498→        );
499→        if (orphanedNotMerged.length > 0) {
500→          console.log(
501→            chalk.yellow(
502→              `  Abandoned (no merge): ${orphanedNotMerged.map((n) => `#${n}`).join(", ")}`,
503→            ),
504→          );
505→        }
506→      }
507→
508→      if (removedCount > 0) {
509→        const removedNotMerged = result.removed.filter(
510→          (n) => !result.merged.includes(n),
511→        );
512→        if (removedNotMerged.length > 0) {
513→          console.log(
514→            chalk.gray(
515→              `  Removed: ${removedNotMerged.map((n) => `#${n}`).join(", ")}`,
516→            ),
517→          );
518→        }
519→      }
520→
521→      if (dryRun) {
522→        console.log(
523→          chalk.gray("\nRun without --dry-run to apply these changes."),
524→        );
525→        if (!removeAll && orphanedCount > 0) {
526→          console.log(
527→            chalk.gray(
528→              "Use --all to remove both merged and abandoned entries.",
529→            ),
530→          );
531→        }
532→      }
533→    }
534→  } else {
535→    console.log(chalk.red(`✗ Cleanup failed: ${result.error}`));
536→  }
537→}
