 40→  createPhaseState,
 41→  updateAcceptanceCriteriaSummary,
 42→} from "./state-schema.js";
 43→import type { ScopeAssessment } from "../scope/types.js";
 44→
 45→export interface StateManagerOptions {
 46→  /** Path to state file (default: .sequant/state.json) */
 47→  statePath?: string;
 48→  /** Enable verbose logging */
 49→  verbose?: boolean;
 50→  /** Lock acquisition timeout in ms (default: 5000) */
 51→  lockTimeout?: number;
 52→}
 53→
 54→/**
 55→ * Manages persistent workflow state
 56→ */
 57→export class StateManager {
 58→  private statePath: string;
 59→  private verbose: boolean;
 60→  private cachedState: WorkflowState | null = null;
 61→  private lockTimeout: number;
 62→
 63→  constructor(options: StateManagerOptions = {}) {
 64→    this.statePath = options.statePath ?? STATE_FILE_PATH;
 65→    this.verbose = options.verbose ?? false;
 66→    this.lockTimeout = options.lockTimeout ?? 5000;
 67→  }
 68→
 69→  /**
 70→   * Execute a callback while holding an exclusive file lock.
 71→   *
 72→   * Ensures that concurrent processes serialize their read-modify-write
 73→   * cycles on state.json. The cache is cleared before executing the
 74→   * callback so the latest on-disk state is read.
 75→   */
 76→  private async withLock<T>(fn: () => Promise<T>): Promise<T> {
 77→    const lockPath = this.statePath + ".lock";
 78→    await this.acquireLock(lockPath);
 79→    try {
 80→      // Clear cache so we read the latest on-disk state
 81→      this.clearCache();
 82→      return await fn();
 83→    } finally {
 84→      this.releaseLock(lockPath);
 85→    }
 86→  }
 87→
 88→  private async acquireLock(lockPath: string): Promise<void> {
 89→    const start = Date.now();
 90→    const retryDelay = 50; // ms
 91→
 92→    // Ensure directory exists for lock file
 93→    const dir = path.dirname(lockPath);
 94→    if (!fs.existsSync(dir)) {
 95→      fs.mkdirSync(dir, { recursive: true });
 96→    }
 97→
 98→    while (true) {
 99→      try {
100→        // O_EXCL: fail atomically if file already exists
101→        const fd = fs.openSync(lockPath, "wx");
102→        fs.writeSync(fd, String(process.pid));
103→        fs.closeSync(fd);
104→        return; // Lock acquired
105→      } catch (err: unknown) {
106→        const code = (err as NodeJS.ErrnoException).code;
107→        if (code !== "EEXIST") throw err;
108→
109→        // Check for stale lock (older than timeout)
110→        try {
111→          const stat = fs.statSync(lockPath);
112→          const age = Date.now() - stat.mtimeMs;
113→          if (age > this.lockTimeout) {
114→            // Stale lock — remove and retry
115→            try {
116→              fs.unlinkSync(lockPath);
117→            } catch {
118→              // Another process may have removed it
119→            }
120→            continue;
121→          }
122→        } catch {
123→          // Lock file disappeared between open and stat — retry
124→          continue;
125→        }
126→
127→        if (Date.now() - start > this.lockTimeout) {
128→          throw new Error(
129→            `Timeout acquiring state lock after ${this.lockTimeout}ms`,
130→          );
131→        }
132→
133→        // Wait and retry
134→        await new Promise((resolve) => setTimeout(resolve, retryDelay));
135→      }
136→    }
137→  }
138→
139→  private releaseLock(lockPath: string): void {
140→    try {
141→      fs.unlinkSync(lockPath);
142→    } catch {
143→      // Ignore — lock may have been cleaned up by stale detection
144→    }
145→  }
146→
147→  /**
148→   * Get the full path to the state file
149→   */
150→  getStatePath(): string {
151→    return this.statePath;
152→  }
153→
154→  /**
155→   * Read the current workflow state
156→   *
157→   * Returns empty state if file doesn't exist.
158→   * Throws on parse errors.
159→   */
160→  async getState(): Promise<WorkflowState> {
161→    // Return cached state if available
162→    if (this.cachedState) {
163→      return this.cachedState;
164→    }
165→
166→    if (!fs.existsSync(this.statePath)) {
167→      const emptyState = createEmptyState();
168→      this.cachedState = emptyState;
169→      return emptyState;
170→    }
171→
172→    try {
173→      const content = fs.readFileSync(this.statePath, "utf-8");
174→      const parsed = JSON.parse(content);
175→      const state = WorkflowStateSchema.parse(parsed);
176→      this.cachedState = state;
177→      return state;
178→    } catch (error) {
179→      if (error instanceof SyntaxError) {
