          chalk.gray("\nRun without --dry-run to apply these changes."),
        );
        if (!removeAll && orphanedCount > 0) {
          console.log(
            chalk.gray(
              "Use --all to remove both merged and abandoned entries.",
            ),
          );
        }
      }
    }
  } else {
    console.log(chalk.red(`✗ Cleanup failed: ${result.error}`));
  }
}

